import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import api from '../../services/api';
import ClienteForm from '../../components/ClienteForm';

function EditarCliente() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [cliente, setCliente] = useState(null);
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    const carregarCliente = async () => {
      try {
        const response = await api.buscarCliente(id);
        setCliente(response.data);
      } catch (error) {
        alert('Erro ao carregar cliente: ' + error.message);
        navigate('/clientes');
      }
    };
    carregarCliente();
  }, [id, navigate]);

  const handleSubmit = async (formData) => {
    setIsLoading(true);
    try {
      await api.atualizarCliente(id, formData);
      navigate('/clientes');
    } catch (error) {
      alert('Erro ao atualizar cliente: ' + error.message);
    } finally {
      setIsLoading(false);
    }
  };

  if (!cliente) return <div>Carregando...</div>;

  return (
    <div>
      <h1>Editar Cliente</h1>
      <ClienteForm cliente={cliente} onSubmit={handleSubmit} isLoading={isLoading} />
    </div>
  );
}

export default EditarCliente;
